// // This module checks if the temperature is below the threshold and outputs 1 if it is.
module temperature_shutdown(  
    input [3:0] temperature,  
    output reg shutdown  
);  
    always @(*) begin  
        if (temperature > 4'd10)  
            shutdown = 1;  
        else  
            shutdown = 0;  
    end  
endmodule
